            <motion.article initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.18 }} className='border border-emerald-300/20 bg-emerald-300/8 p-5'>
              <div className='mb-3 flex items-center justify-between gap-3'>
