import { useMemo, useState } from 'react';

type Range = '7d' | '30d' | '90d';

type QueueItem = {
  id: number;
  customer: string;
  status: string;
  value: string;
  owner: string;
};

const metricsByRange: Record<Range, Array<{ label: string; value: string; note: string }>> = {
  '7d': [
    { label: 'Revenue', value: '$48.2k', note: '+8.4% vs prior week' },
    { label: 'Approval queue', value: '18', note: '5 need action today' },
    { label: 'Resolution time', value: '2.8h', note: 'median first response' },
  ],
  '30d': [
    { label: 'Revenue', value: '$186k', note: '+12.1% vs prior month' },
    { label: 'Approval queue', value: '64', note: '14 need action today' },
    { label: 'Resolution time', value: '3.2h', note: 'median first response' },
  ],
  '90d': [
    { label: 'Revenue', value: '$542k', note: '+18.9% vs prior quarter' },
    { label: 'Approval queue', value: '141', note: '31 need action today' },
    { label: 'Resolution time', value: '3.6h', note: 'median first response' },
  ],
};

const pipeline = [
  { label: 'Qualified', value: 42, accent: '#38bdf8' },
  { label: 'Review', value: 28, accent: '#a78bfa' },
  { label: 'Approved', value: 17, accent: '#22c55e' },
  { label: 'Escalated', value: 6, accent: '#f97316' },
];

const queue: QueueItem[] = [
  { id: 1, customer: 'Northwind Travel', status: 'Needs review', value: '$8.4k', owner: 'Mila' },
  { id: 2, customer: 'Fjord Health', status: 'Waiting on docs', value: '$14.2k', owner: 'Jon' },
  { id: 3, customer: 'Studio Forma', status: 'Ready to approve', value: '$5.6k', owner: 'Ari' },
  { id: 4, customer: 'Atlas Ops', status: 'Escalated', value: '$11.3k', owner: 'Sana' },
];

const notes = [
  'Keep the top KPIs obvious before adding more charts.',
  'Queue + owner context should sit close to the metrics that explain them.',
  'Use this as the admin/ops dashboard base before wiring real data.',
];

export default function App() {
  const [range, setRange] = useState<Range>('30d');
  const activeMetrics = useMemo(() => metricsByRange[range], [range]);

  return (
    <main className="dashboard-shell">
      <section className="hero-card">
        <div>
          <p className="eyebrow">Dashboard archetype</p>
          <h1>Operational clarity with KPIs, queue state, and decision lanes.</h1>
          <p className="lede">A composed dashboard shell for analytics-heavy or ops-heavy apps, with metrics first, a real review queue, and visible ownership instead of empty chart wallpaper.</p>
          <div className="range-row">
            {(['7d', '30d', '90d'] as const).map((option) => (
              <button key={option} type="button" className={range === option ? "chip active" : "chip"} onClick={() => setRange(option)}>{option}</button>
            ))}
          </div>
        </div>
        <aside className="hero-note">
          <span>Operator view</span>
          <strong>{queue.length} live items</strong>
          <p>Use this base for admin dashboards, internal tools, analytics surfaces, or approval workflows.</p>
        </aside>
      </section>

      <section className="metric-grid">
        {activeMetrics.map((metric) => (
          <article key={metric.label} className="metric-card">
            <span>{metric.label}</span>
            <strong>{metric.value}</strong>
            <small>{metric.note}</small>
          </article>
        ))}
      </section>

      <section className="content-grid">
        <section className="card">
          <div className="section-head">
            <div>
              <p className="eyebrow">Pipeline</p>
              <h2>Current flow</h2>
            </div>
            <span>4 stages</span>
          </div>
          <div className="pipeline-grid">
            {pipeline.map((item) => (
              <article key={item.label} className="pipeline-card">
                <div className="pipeline-bar" style={{ background: item.accent, width: `${Math.max(item.value * 2, 22)}px` }} />
                <strong>{item.value}</strong>
                <span>{item.label}</span>
              </article>
            ))}
          </div>
        </section>

        <section className="card">
          <div className="section-head">
            <div>
              <p className="eyebrow">Review queue</p>
              <h2>Approvals and follow-up</h2>
            </div>
          </div>
          <div className="queue-list">
            {queue.map((item) => (
              <article key={item.id} className="queue-card">
                <div>
                  <strong>{item.customer}</strong>
                  <p>{item.status}</p>
                </div>
                <div className="queue-meta">
                  <span>{item.value}</span>
                  <small>{item.owner}</small>
                </div>
              </article>
            ))}
          </div>
        </section>

        <aside className="card note-stack">
          <p className="eyebrow">Build notes</p>
          <ul className="note-list">
            {notes.map((note) => (
              <li key={note}>{note}</li>
            ))}
          </ul>
        </aside>
      </section>
    </main>
  );
}
