import { useMemo, useState } from 'react';

type Appointment = {
  id: number;
  client: string;
  slot: string;
  service: string;
  status: string;
};

const weeklySlots = [
  { day: 'Mon', open: '09:00-16:00', note: 'Consult calls + follow-up' },
  { day: 'Tue', open: '10:00-18:00', note: 'On-site sessions' },
  { day: 'Thu', open: '08:30-15:30', note: 'Remote booking blocks' },
  { day: 'Fri', open: '11:00-17:00', note: 'Short intro appointments' },
];

const appointments: Appointment[] = [
  { id: 1, client: 'North Studio', slot: 'Tue 10:30', service: 'Discovery call', status: 'Confirmed' },
  { id: 2, client: 'Lina Berg', slot: 'Thu 09:00', service: 'Portfolio review', status: 'Needs reminder' },
  { id: 3, client: 'Atlas Retreat', slot: 'Fri 13:15', service: 'Planning session', status: 'Deposit pending' },
];

const checklist = [
  'Show next available slots clearly before adding deeper settings.',
  'Keep appointment status and client context close together.',
  'This is the right base before payments, reminders, or calendar sync.',
];

export default function App() {
  const [selectedDay, setSelectedDay] = useState(weeklySlots[0]?.day ?? 'Mon');
  const selectedSchedule = useMemo(() => weeklySlots.find((slot) => slot.day === selectedDay) ?? weeklySlots[0], [selectedDay]);

  return (
    <main className="booking-shell">
      <section className="hero-card">
        <div>
          <p className="eyebrow">Booking app archetype</p>
          <h1>Let people book time without losing the shape of your week.</h1>
          <p className="lede">A booking-first app shell for consultations, appointments, and time-slot management.</p>
          <div className="day-row">
            {weeklySlots.map((slot) => (
              <button key={slot.day} type="button" className={selectedDay === slot.day ? "chip active" : "chip"} onClick={() => setSelectedDay(slot.day)}>{slot.day}</button>
            ))}
          </div>
        </div>
        <aside className="hero-note">
          <span>Selected schedule</span>
          <strong>{selectedSchedule.day}</strong>
          <p>{selectedSchedule.open}</p>
          <small>{selectedSchedule.note}</small>
        </aside>
      </section>

      <section className="content-grid">
        <section className="card">
          <div className="section-head">
            <div>
              <p className="eyebrow">Availability</p>
              <h2>Weekly open blocks</h2>
            </div>
          </div>
          <div className="slot-list">
            {weeklySlots.map((slot) => (
              <article key={slot.day} className={selectedDay === slot.day ? "slot-card is-active" : "slot-card"}>
                <div>
                  <strong>{slot.day}</strong>
                  <p>{slot.note}</p>
                </div>
                <span>{slot.open}</span>
              </article>
            ))}
          </div>
        </section>

        <section className="card">
          <div className="section-head">
            <div>
              <p className="eyebrow">Appointments</p>
              <h2>Upcoming bookings</h2>
            </div>
          </div>
          <div className="appointment-list">
            {appointments.map((appointment) => (
              <article key={appointment.id} className="appointment-card">
                <div>
                  <strong>{appointment.client}</strong>
                  <p>{appointment.service}</p>
                </div>
                <div className="appointment-meta">
                  <span>{appointment.slot}</span>
                  <small>{appointment.status}</small>
                </div>
              </article>
            ))}
          </div>
        </section>

        <aside className="card note-stack">
          <p className="eyebrow">Build notes</p>
          <ul className="note-list">
            {checklist.map((item) => (
              <li key={item}>{item}</li>
            ))}
          </ul>
          <div className="cta-panel">
            <span>Next slice</span>
            <strong>Add reminders + intake form</strong>
          </div>
        </aside>
      </section>
    </main>
  );
}
