import { useMemo, useState } from 'react';

type Intensity = 'Recovery' | 'Build' | 'Peak';

type Session = {
  id: number;
  day: string;
  title: string;
  focus: string;
  duration: number;
  intensity: Intensity;
  completed: boolean;
};

const initialPlan: Session[] = [
  { id: 1, day: 'Mon', title: 'Lower body strength', focus: 'Front squat + split squat + carries', duration: 64, intensity: 'Build', completed: true },
  { id: 2, day: 'Tue', title: 'Zone 2 run', focus: 'Steady aerobic base with nasal breathing pace', duration: 38, intensity: 'Recovery', completed: true },
  { id: 3, day: 'Thu', title: 'Upper body push-pull', focus: 'Bench, row, press, and shoulder health work', duration: 58, intensity: 'Build', completed: false },
  { id: 4, day: 'Sat', title: 'Hill repeat session', focus: 'Short uphill efforts with long walk-back recovery', duration: 46, intensity: 'Peak', completed: false },
];

const progressNotes = [
  { label: 'Consistency', value: '11 days', note: 'current streak' },
  { label: 'Weekly load', value: '206 min', note: 'planned volume' },
  { label: 'PR watch', value: 'Front squat +5 kg', note: 'last two weeks' },
];

const recoveryChecklist = [
  'Sleep target: 8 hours before the hill session',
  'Prepare next-day workout clothes tonight',
  'Keep Friday mobility easy instead of adding more volume',
];

export default function App() {
  const [plan, setPlan] = useState(initialPlan);
  const [selectedFilter, setSelectedFilter] = useState<'All' | Intensity>('All');

  const completedCount = useMemo(() => plan.filter((session) => session.completed).length, [plan]);
  const visiblePlan = useMemo(() => (
    selectedFilter === 'All' ? plan : plan.filter((session) => session.intensity === selectedFilter)
  ), [plan, selectedFilter]);
  const nextSession = useMemo(() => plan.find((session) => !session.completed) ?? plan[plan.length - 1], [plan]);

  function toggleSession(id: number) {
    setPlan((current) => current.map((session) => (
      session.id === id
        ? { ...session, completed: !session.completed }
        : session
    )));
  }

  return (
    <main className="tracker-shell">
      <section className="hero-card">
        <div>
          <p className="eyebrow">Personal training tracker</p>
          <h1>Train with structure, not guesswork.</h1>
          <p className="lede">A private workout app focused on weekly structure, session completion, and progress you can use for yourself without admin clutter.</p>
          <div className="hero-pills">
            <span>Plan the week</span>
            <span>Log sessions</span>
            <span>Review progress</span>
          </div>
        </div>
        <aside className="hero-note">
          <span>Next session</span>
          <strong>{nextSession.title}</strong>
          <p>{nextSession.focus}</p>
          <small>{nextSession.day} • {nextSession.duration} min • {nextSession.intensity}</small>
        </aside>
      </section>

      <section className="metric-grid">
        {progressNotes.map((item) => (
          <article key={item.label} className="metric-card">
            <span>{item.label}</span>
            <strong>{item.value}</strong>
            <small>{item.note}</small>
          </article>
        ))}
      </section>

      <section className="content-grid">
        <section className="card">
          <div className="section-head">
            <div>
              <p className="eyebrow">Weekly plan</p>
              <h2>{completedCount}/{plan.length} sessions done</h2>
            </div>
            <div className="filter-row">
              {(['All', 'Recovery', 'Build', 'Peak'] as const).map((filter) => (
                <button
                  key={filter}
                  type="button"
                  className={selectedFilter === filter ? "chip active" : "chip"}
                  onClick={() => setSelectedFilter(filter)}
                >
                  {filter}
                </button>
              ))}
            </div>
          </div>
          <div className="session-list">
            {visiblePlan.map((session) => (
              <button key={session.id} type="button" className={session.completed ? "session-card is-complete" : "session-card"} onClick={() => toggleSession(session.id)}>
                <div>
                  <span className="session-day">{session.day}</span>
                  <strong>{session.title}</strong>
                  <p>{session.focus}</p>
                </div>
                <div className="session-meta">
                  <span>{session.duration} min</span>
                  <span>{session.intensity}</span>
                  <span>{session.completed ? "Done" : "Tap to log"}</span>
                </div>
              </button>
            ))}
          </div>
        </section>

        <section className="card side-stack">
          <div>
            <p className="eyebrow">Recovery cues</p>
            <h2>Keep the hard day hard.</h2>
          </div>
          <ul className="checklist">
            {recoveryChecklist.map((item) => (
              <li key={item}>{item}</li>
            ))}
          </ul>
          <div className="progress-panel">
            <span>Momentum</span>
            <strong>78%</strong>
            <p>Your plan is on pace if you complete the Thursday lift before 20:00.</p>
          </div>
        </section>
      </section>
    </main>
  );
}
