```tsx title="src/App.tsx"
import { useMemo, useState } from 'react';

type Profile = {
  id: number;
  name: string;
  age: number;
  city: string;
  vibe: string;
  blurb: string;
  interests: string[];
  gradient: string;
};

const profiles: Profile[] = [
  { id: 1, name: 'Sana', age: 29, city: 'Oslo', vibe: 'Slow mornings, sharp humour, coastal weekends.', blurb: 'Product designer who likes winter sea dips, bookstore dates, and low-key city walks.', interests: ['Sea sauna', 'Film photos', 'Thai curry'], gradient: 'linear-gradient(135deg, #f97316, #fb7185)' },
  { id: 2, name: 'Jonas', age: 31, city: 'Bergen', vibe: 'Trail runs, espresso, and good conversation.', blurb: 'Usually planning a cabin trip or a dinner party with too much olive oil and good bread.', interests: ['Trail running', 'Espresso bars', 'Cabin trips'], gradient: 'linear-gradient(135deg, #38bdf8, #818cf8)' },
  { id: 3, name: 'Maja', age: 27, city: 'Trondheim', vibe: 'Warm energy with a calm social battery.', blurb: 'Works in publishing, loves live music, and picks restaurants based on lighting almost as much as food.', interests: ['Live sets', 'Late dinners', 'Bookshops'], gradient: 'linear-gradient(135deg, #22c55e, #14b8a6)' },
];

const openers = [
  'Ask about their ideal slow Sunday.',
  'Swap favourite low-key Oslo spots.',
  'Start with travel or trail plans, not small talk.',
];

export default function App() {
  const [index, setIndex] = useState(0);
  const [matches, setMatches] = useState<Profile[]>([]);
  const [filter, setFilter] = useState<'Nearby' | 'New' | 'Matches'>('Nearby');

  const currentProfile = profiles[index] ?? null;
  const remaining = Math.max(profiles.length - index, 0);
  const topMatch = useMemo(() => matches[0] ?? null, [matches]);

  function swipe(action: 'pass' | 'like') {
    if (!currentProfile) return;
    if (action === "like" && !matches.some((profile) => profile.id === currentProfile.id)) {
      setMatches((current) => [currentProfile, ...current]);
    }
    setIndex((current) => current + 1);
  }

  return (
    <main className="matching-shell">
      <section className="hero-card">
        <div>
          <p className="eyebrow">Matching app archetype</p>
          <h1>Browse profiles, match quickly, and move into real conversation.</h1>
          <p className="lede">A swipe-based product shell with a profile deck, match queue, and chat-ready follow-up prompts instead of a generic landing page.</p>
          <div className="hero-pills">
            <span>Profile deck</span>
            <span>Swipe actions</span>
            <span>Matches + chat</span>
          </div>
        </div>
        <aside className="hero-note">
          <span>Queue state</span>
          <strong>{remaining} profiles left</strong>
          <p>{topMatch ? `Latest match: ${topMatch.name} from ${topMatch.city}` : "Like someone to start the match queue."}</p>
        </aside>
      </section>

      <section className="content-grid">
        <section className="deck-card">
          <div className="deck-head">
            <div>
              <p className="eyebrow">Swipe queue</p>
              <h2>{filter}</h2>
            </div>
            <div className="filter-row">
              {(['Nearby', 'New', 'Matches'] as const).map((label) => (
                <button key={label} type="button" className={filter === label ? "chip active" : "chip"} onClick={() => setFilter(label)}>{label}</button>
              ))}
            </div>
          </div>

          {currentProfile ? (
            <article className="profile-card">
              <div className="profile-visual" style={{ background: currentProfile.gradient }} />
              <div className="profile-copy">
                <div>
                  <h3>{currentProfile.name}, {currentProfile.age}</h3>
                  <span>{currentProfile.city}</span>
                </div>
                <p className="profile-vibe">{currentProfile.vibe}</p>
                <p>{currentProfile.blurb}</p>
                <div className="tag-row">
                  {currentProfile.interests.map((interest) => (
                    <span key={interest}>{interest}</span>
                  ))}
                </div>
                <div className="action-row">
                  <button type="button" className="secondary" onClick={() => swipe("pass")}>Pass</button>
                  <button type="button" className="primary" onClick={() => swipe("like")}>Like</button>
                </div>
              </div>
            </article>
          ) : (
            <article className="profile-card profile-empty">
              <h3>You reached the end of the deck.</h3>
              <p>Reset the queue or move into matches and chat as the next feature slice.</p>
            </article>
          )}
        </section>

        <aside className="side-stack">
          <section className="card">
            <p className="eyebrow">Matches</p>
            <h2>{matches.length} active</h2>
            <div className="match-list">
              {matches.length > 0 ? matches.map((profile) => (
                <div key={profile.id} className="match-card">
                  <strong>{profile.name}</strong>
                  <span>{profile.city}</span>
                </div>
              )) : <p className="empty-copy">Your next like should appear here immediately.</p>}
            </div>
          </section>

          <section className="card">
            <p className="eyebrow">Conversation starters</p>
            <ul className="opener-list">
              {openers.map((item) => (
                <li key={item}>{item}</li>
              ))}
            </ul>
          </section>
        </aside>
      </section>
    </main>
  );
}
