textarea:focus-visible,
button:focus-visible {
  outline: 2px solid rgba(255, 132, 112, 0.42);
  outline-offset: 2px;
}

textarea {
  resize: vertical;
  min-height: 10rem;
}

button {
  border: 0;
  border-radius: 18px;
  background: linear-gradient(135deg, #ff6b57, #ff8866);
  color: #130f12;
  padding: 0.95rem 1rem;
  cursor: pointer;
  font-weight: 700;
  box-shadow: 0 18px 34px rgba(255, 107, 87, 0.18);
}

.social-shell {
  max-width: 1560px;
  margin: 0 auto;
  padding: 1.75rem 1.35rem 2.5rem;
}

.social-header {
  display: grid;
  grid-template-columns: minmax(0, 1.15fr) minmax(20rem, 0.85fr);
  gap: 1rem;
  align-items: end;
  padding: 1.6rem;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 34px;
  background: linear-gradient(135deg, rgba(23, 23, 31, 0.94), rgba(19, 20, 28, 0.86));
  box-shadow: 0 26px 46px rgba(0, 0, 0, 0.28);
}

.eyebrow,
.label,
.count,
.story-meta,
.featured-label,
.ticker span {
  text-transform: uppercase;
  letter-spacing: 0.18em;
  font-size: 0.72rem;
}

.eyebrow,
.label,
.ticker span {
  color: #f4a792;
}

h1,
h2,
h3,
strong {
  margin: 0;
  font-family: 'Aptos Display', 'Segoe UI Variable Display', sans-serif;
}

h1 {
  max-width: 8ch;
  font-size: clamp(3.2rem, 7vw, 6rem);
  line-height: 0.9;
  letter-spacing: -0.06em;
}

.lede,
.story p,
.pulse-item,
.featured-card p {
  color: #d6cac0;
  line-height: 1.72;
}

.lede {
  max-width: 54ch;
  margin-top: 1rem;
  font-size: 1.05rem;
}

.ticker {
  display: flex;
  flex-wrap: wrap;
  justify-content: flex-end;
  gap: 0.7rem;
}

.ticker span {
  padding: 0.72rem 0.95rem;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.02);
}

.social-grid {
  display: grid;
  grid-template-columns: minmax(19rem, 22rem) minmax(0, 1fr) minmax(18rem, 21rem);
  gap: 1rem;
  margin-top: 1rem;
  align-items: start;
}

.composer-rail,
.feed-stage,
.pulse-rail {
  padding: 1.1rem;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 28px;
  background: linear-gradient(180deg, rgba(18, 18, 24, 0.92), rgba(15, 16, 22, 0.88));
  box-shadow: 0 20px 38px rgba(0, 0, 0, 0.22);
}

.composer-rail {
  position: sticky;
  top: 1rem;
}

.composer-rail,
.feed-list,
.pulse-list {
  display: grid;
  gap: 0.95rem;
}

.section-head {
  margin-bottom: 0.85rem;
}

.section-head h2 {
  margin-top: 0.35rem;
  font-size: 1.5rem;
}

.feed-head {
  display: flex;
  justify-content: space-between;
  gap: 1rem;
  align-items: end;
}

.feed-list {
  gap: 1rem;
}

.story {
  padding: 1.15rem;
  border: 1px solid rgba(255, 255, 255, 0.07);
