  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 22px;
  background: rgba(255, 255, 255, 0.03);
}

.featured-card {
  border-color: rgba(255, 108, 84, 0.22);
  background: linear-gradient(180deg, rgba(255, 108, 84, 0.08), rgba(255, 255, 255, 0.03));
}

.featured-card strong {
  display: block;
  margin-top: 0.6rem;
