}

@media (max-width: 1160px) {
  .social-header,
  .social-grid {
    grid-template-columns: 1fr;
  }

  .ticker {
    justify-content: flex-start;
  }

  .composer-rail {
    position: static;
  }
}

@media (max-width: 720px) {
  .social-shell {
    padding: 1rem 0.85rem 1.5rem;
  }

  .social-header,
  .composer-rail,
  .feed-stage,
  .pulse-rail {
    border-radius: 24px;
  }
}
